PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "is_admin" tinyint(1) not null default '0', "role" varchar not null default 'order_manager');
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "categories" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "product_images" ("id" integer primary key autoincrement not null, "product_id" integer not null, "file_name" varchar not null, "file_path" varchar not null, "is_featured" tinyint(1) not null default '0', "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "client_prices" ("id" integer primary key autoincrement not null, "client_id" integer not null, "product_id" integer not null, "price" numeric not null, "notes" text, "created_at" datetime, "updated_at" datetime, "allow_piece_sales" tinyint(1) not null default '0', foreign key("client_id") references "clients"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "order_items" ("id" integer primary key autoincrement not null, "order_id" integer not null, "product_id" integer, "product_name" varchar not null, "quantity" integer not null, "sold_by_package" tinyint(1) not null default '0', "pieces_per_package" integer, "unit_price" numeric, "total_price" numeric, "created_at" datetime, "updated_at" datetime, "discount_amount" numeric not null default '0', "discount_type" varchar, "discount_value" numeric, "unit_type" varchar, foreign key("order_id") references "orders"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "suppliers" ("id" integer primary key autoincrement not null, "name" varchar not null, "contact_person" varchar, "email" varchar, "phone" varchar, "address" varchar, "notes" text, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "deleted_at" datetime);
CREATE TABLE IF NOT EXISTS "products" ("id" integer primary key autoincrement not null, "category_id" integer not null, "name" varchar not null, "slug" varchar not null, "description" text, "price" numeric, "image_path" varchar, "is_featured" tinyint(1) not null default ('0'), "created_at" datetime, "updated_at" datetime, "sort_order" integer not null default ('0'), "sold_by_package" tinyint(1) not null default ('0'), "pieces_per_package" integer, "supplier_id" integer, "stock_quantity" integer not null default '0', "cost_price" numeric, "min_stock_level" integer not null default '0', "deleted_at" datetime, "size" varchar, "liters" varchar, "barcode" varchar, foreign key("category_id") references categories("id") on delete cascade on update no action, foreign key("supplier_id") references "suppliers"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "stock_receipts" ("id" integer primary key autoincrement not null, "receipt_number" varchar not null, "supplier_id" integer not null, "receipt_date" date not null, "notes" text, "total_amount" numeric not null default '0', "total_items" integer not null default '0', "status" varchar not null default 'pending', "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("supplier_id") references "suppliers"("id") on delete restrict);
CREATE TABLE IF NOT EXISTS "stock_movements" ("id" integer primary key autoincrement not null, "product_id" integer not null, "movement_type" varchar not null, "stock_receipt_id" integer, "order_id" integer, "quantity" integer not null, "unit_cost" numeric, "total_cost" numeric, "stock_before" integer not null, "stock_after" integer not null, "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("product_id") references "products"("id") on delete cascade, foreign key("stock_receipt_id") references "stock_receipts"("id") on delete set null, foreign key("order_id") references "orders"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "supplier_invoices" ("id" integer primary key autoincrement not null, "invoice_number" varchar not null, "supplier_id" integer not null, "stock_receipt_id" integer, "invoice_date" date not null, "due_date" date, "subtotal" numeric not null default '0', "has_vat" tinyint(1) not null default '0', "vat_rate" numeric not null default '18', "vat_amount" numeric not null default '0', "total_amount" numeric not null default '0', "status" varchar not null default 'pending', "paid_date" date, "notes" text, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "deleted_reason" text, "restored_at" datetime, "restored_reason" text, "deleted_by" varchar, foreign key("supplier_id") references "suppliers"("id") on delete restrict, foreign key("stock_receipt_id") references "stock_receipts"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "stock_receipt_items" ("id" integer primary key autoincrement not null, "stock_receipt_id" integer not null, "product_id" integer not null, "quantity" numeric not null, "unit_cost" numeric not null, "total_cost" numeric not null, "notes" text, "created_at" datetime, "updated_at" datetime, "unit_type" varchar, foreign key("product_id") references products("id") on delete cascade on update no action, foreign key("stock_receipt_id") references stock_receipts("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "supplier_invoice_items" ("id" integer primary key autoincrement not null, "supplier_invoice_id" integer not null, "product_id" integer, "product_name" varchar not null, "quantity" numeric not null, "unit_price" numeric not null, "total_price" numeric not null, "notes" text, "created_at" datetime, "updated_at" datetime, "unit_type" varchar, foreign key("product_id") references products("id") on delete set null on update no action, foreign key("supplier_invoice_id") references supplier_invoices("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "client_locations" ("id" integer primary key autoincrement not null, "client_id" integer not null, "unit_name" varchar not null, "street_number" varchar, "phone" varchar, "viber" varchar, "notes" text, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("client_id") references "clients"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "orders" ("id" integer primary key autoincrement not null, "client_id" integer, "order_number" varchar not null, "customer_name" varchar not null, "business_name" varchar not null, "city" varchar not null, "phone" varchar, "viber" varchar, "total_items" integer not null default ('0'), "total_amount" numeric, "summary" text, "status" varchar not null default ('ruajtur'), "created_at" datetime, "updated_at" datetime, "is_paid" tinyint(1) not null default ('0'), "paid_at" datetime, "subtotal" numeric, "discount_amount" numeric not null default ('0'), "discount_type" varchar, "discount_value" numeric, "fiscal_number" varchar, "has_vat" tinyint(1) not null default ('0'), "vat_amount" numeric, "amount_before_vat" numeric, "deleted_at" datetime, "client_location_id" integer, "location_unit_name" varchar, "location_street_number" varchar, "location_phone" varchar, "location_viber" varchar, "location_city" varchar, foreign key("client_id") references clients("id") on delete set null on update no action, foreign key("client_location_id") references "client_locations"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "clients" ("id" integer primary key autoincrement not null, "name" varchar not null, "store_name" varchar, "city" varchar, "phone" varchar, "viber" varchar, "email" varchar, "notes" text, "is_active" tinyint(1) not null default ('1'), "created_at" datetime, "updated_at" datetime, "fiscal_number" varchar, "allow_piece_sales" tinyint(1) not null default ('0'), "deleted_at" datetime, "street_number" varchar, "unit" varchar, "password" varchar);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "categories_slug_unique" on "categories" ("slug");
CREATE UNIQUE INDEX "client_prices_client_id_product_id_unique" on "client_prices" ("client_id", "product_id");
CREATE INDEX "personal_access_tokens_tokenable_type_tokenable_id_index" on "personal_access_tokens" ("tokenable_type", "tokenable_id");
CREATE UNIQUE INDEX "personal_access_tokens_token_unique" on "personal_access_tokens" ("token");
CREATE INDEX "personal_access_tokens_expires_at_index" on "personal_access_tokens" ("expires_at");
CREATE UNIQUE INDEX "products_slug_unique" on "products" ("slug");
CREATE UNIQUE INDEX "stock_receipts_receipt_number_unique" on "stock_receipts" ("receipt_number");
CREATE UNIQUE INDEX "supplier_invoices_invoice_number_unique" on "supplier_invoices" ("invoice_number");
CREATE UNIQUE INDEX "orders_order_number_unique" on "orders" ("order_number");
CREATE UNIQUE INDEX "clients_phone_unique" on "clients" ("phone");
CREATE UNIQUE INDEX "clients_email_unique" on "clients" ("email");
COMMIT;
