INSERT INTO products VALUES(3,3,'Folie Alumini 9 Micron','folie-alumini-9-micron','Folie alumini profesionale me trashësi 9 micron për ruajtjen dhe mbrojtjen e ushqimit. Cilësi e lartë, rezistente ndaj temperaturës dhe të sigurta për kontakt me ushqim. Ideal për ruajtjen e ushqimit, përgatitjen e pjatave dhe përdorim profesional në kuzhinë. Siguron mbrojtje të plotë nga ajri dhe lagështia.',NULL,'/images/IMG_6814.jpeg',1,'2025-11-26 05:20:19','2026-02-19 05:02:32',0,1,12,NULL,0,3.799999999999999823,0,NULL,NULL,NULL,'GT-FOLIE-ALUMINI-9-MICRON');
INSERT INTO products VALUES(4,4,'Letër Kuzhine NUSH 2 Shtresa','leter-kuzhine-nush-2-shtresa',replace(replace('Letër kuzhine NUSH me 2 shtresa, 100% celulozë të pastër. Absorbueshme, të buta dhe të qëndrueshme. Ideal për pastrimin e kuzhinës, tavolinave dhe sipërfaqeve të tjera. Materiali i pastër siguron siguri dhe higjienë të plotë. Përshtatet për përdorim profesional dhe shtëpiak.\r\n\r\n**Paketimi:** Shitet vetëm në komplete. 1 kompleti = 12 copa.','\r',char(13)),'\n',char(10)),NULL,'/images/Pallomat/XL/foto1.png',1,'2025-11-26 05:20:19','2026-03-01 22:01:34',0,1,12,NULL,0,NULL,0,NULL,NULL,NULL,'3900000000048');
INSERT INTO products VALUES(5,6,'Baby Wipes Canéa Aqua Pure','baby-wipes-canea-aqua-pure','Peceta të lagura Canéa Aqua Pure për fëmijë. Formula e butë dhe e sigurt për lëkurën e ndjeshme të fëmijëve. Përmbajnë ujë të pastër dhe përbërës natyralë. Ideal për pastrimin e fëmijëve, si dhe për përdorim në kuzhinë për pastrimin e duarve dhe sipërfaqeve. Paketimi praktik dhe i lehtë për transport.',0.6500000000000000222,'/images/IMG_6818.jpeg',1,'2025-11-26 05:20:19','2026-02-19 06:24:28',0,1,10,NULL,0,0.5500000000000000444,0,NULL,NULL,NULL,'3900000000055');
