INSERT INTO products VALUES(22,7,'Mbulesë Tavoline NUSH','mbulese-tavoline-nush','Mbulesë tavoline LDP (Low Density Polyethylene) për mbrojtjen e tavolinave. Materiali i qëndrueshëm dhe i lehtë siguron mbrojtje të plotë nga pika, ndotja dhe dëmtimet. Ideal për restorantet, kafetë, evente dhe përdorim shtëpiak. Lehtë për pastrim dhe përdorim të përsëritur. Transparenca lejon shikimin e dizajnit të tavolinës.',NULL,'/images/Mbulesa Tavoline/foto1.jpg',1,'2025-11-26 05:20:19','2026-03-01 21:54:53',2,1,10,NULL,0,0.5999999999999999778,0,NULL,NULL,NULL,'3904981700200');
INSERT INTO products VALUES(26,7,'Produkt Shtesë 3','produkt-shtese-3','Produkt shtesë i cilësisë së lartë për kuzhinë dhe biznes. Materiali i sigurt dhe i qëndrueshëm siguron përdorim të besueshëm. Ideal për përdorim profesional në restorante, kafetë, markete dhe përdorim shtëpiak. Dizajni praktik dhe funksional. Përshtatet për nevojat e ndryshme të kuzhinës dhe siguron cilësi të lartë në përdorim.',NULL,'/images/IMG_6825.jpeg',0,'2025-11-26 05:20:19','2026-02-19 05:02:32',0,0,NULL,NULL,0,NULL,0,NULL,NULL,NULL,'GT-PRODUKT-SHTESE-3');
INSERT INTO products VALUES(27,1,'Pipëza Transparente për Pije (100Cp - Kompleti 20Cp)','pipeza-transparente-per-pije-100cp-kompleti-20cp',replace('Pipëza transparente të qarta 100Cp për pije të ndryshme. Materiali i pastër dhe i sigurt për përdorim. Të qëndrueshme dhe të lehta. Ideal për kafetë, restorantet, evente dhe përdorim shtëpiak. Transparenca lejon shikimin e pijes dhe krijon një pamje elegante. Përshtatet për pije të nxehta dhe të ftohta.\n\n**Paketimi:** Shitet vetëm në komplete. 1 kompleti = 20 copa.','\n',char(10)),NULL,'/images/IMG_6819.jpeg',0,'2025-11-26 06:46:33','2026-02-19 05:02:32',14,1,20,NULL,0,NULL,0,NULL,NULL,NULL,'GT-PIPEZA-TRANSPARENTE-PER-PIJE-100CP-KOMPLETI-20CP');
