INSERT INTO products VALUES(32,1,'Pipëza Color për Pije (200Cp - Kompleti 20Cp)','pipeza-color-per-pije-200cp-kompleti-20cp',replace('Pipëza me ngjyra të ndryshme 200Cp për pije. Dizajn i bukur dhe i gjallë që i përshtatet çdo ambienti. Të qëndrueshme, të sigurta për përdorim dhe të lehta. Ideal për evente, festa, restorantet dhe kafetë. Ngjyrat e ndryshme lejojnë organizimin dhe dallimin e pijeve të ndryshme. Përshtatet për pije të nxehta dhe të ftohta.\n\n**Paketimi:** Shitet vetëm në komplete. 1 kompleti = 20 copa.','\n',char(10)),NULL,'/images/IMG_6816.jpeg',0,'2025-11-26 06:46:33','2026-02-19 05:02:32',19,1,20,NULL,0,NULL,0,NULL,NULL,NULL,'GT-PIPEZA-COLOR-PER-PIJE-200CP-KOMPLETI-20CP');
INSERT INTO products VALUES(33,1,'Pipëza Te Zi për Pije (500Cp - Kompleti 10Cp)','pipeza-te-zi-per-pije-500cp-kompleti-10cp',replace('Pipëza plastike të zeza 500Cp të cilësisë së lartë për pije të mëdha. Të qëndrueshme, të sigurta për përdorim dhe të lehta. Përshtaten për pije të nxehta dhe të ftohta. Ideal për kafetë, restorantet, evente dhe përdorim shtëpiak. Dizajni elegant i zi i përshtatet me çdo ambient.\n\n**Paketimi:** Shitet vetëm në komplete. 1 kompleti = 10 copa.','\n',char(10)),NULL,'/images/IMG_6822.jpeg',0,'2025-11-26 06:46:33','2026-02-19 05:02:32',20,1,10,NULL,0,NULL,0,NULL,NULL,NULL,'GT-PIPEZA-TE-ZI-PER-PIJE-500CP-KOMPLETI-10CP');
INSERT INTO products VALUES(34,1,'Pipëza Color për Pije (500Cp - Kompleti 10Cp)','pipeza-color-per-pije-500cp-kompleti-10cp',replace('Pipëza me ngjyra të ndryshme 500Cp për pije të mëdha. Dizajn i bukur dhe i gjallë që i përshtatet çdo ambienti. Të qëndrueshme, të sigurta për përdorim dhe të lehta. Ideal për evente, festa, restorantet dhe kafetë. Ngjyrat e ndryshme lejojnë organizimin dhe dallimin e pijeve të ndryshme. Përshtatet për pije të nxehta dhe të ftohta.\n\n**Paketimi:** Shitet vetëm në komplete. 1 kompleti = 10 copa.','\n',char(10)),NULL,'/images/IMG_6816.jpeg',0,'2025-11-26 06:46:33','2026-02-19 05:02:32',21,1,10,NULL,0,NULL,0,NULL,NULL,NULL,'GT-PIPEZA-COLOR-PER-PIJE-500CP-KOMPLETI-10CP');
